import java.util.Arrays;

class Solution {
    /**
     * @param nums The input integer array.
     * @return The minimum total operations required to achieve the maximum number of special indices.
     */
    public static long solve(long[] nums) {
        int n = nums.length;
        if (n < 3) {
            return 0;
        }

        // The maximum number of peaks is achieved by alternating peaks and non-peaks (valleys/bases).
        // Since we can only increase values, the maximum number of non-overlapping peaks is indeed related to ceil((n-2)/2).
        // We test two primary candidates for maximum peak configuration:
        // 1. Peaks at indices 1, 3, 5, ... (starting at index 1)
        // 2. Peaks at indices 2, 4, 6, ... (starting at index 2)

        // We need to simulate the cost for these two fixed target patterns.

        // Case 1: Peaks at 1, 3, 5, ...
        long cost1 = 0;
        long[] currentNums1 = Arrays.copyOf(nums, n);

        // Iterate over potential peak indices i = 1, 3, 5, ...
        for (int i = 1; i <= n - 2; i += 2) {
            // Target: currentNums1[i] > max(currentNums1[i-1], currentNums1[i+1])

            // Since we are iterating sequentially, the neighbors currentNums1[i-1] and currentNums1[i+1]
            // might have been modified by previous operations if i-1 or i+1 was a peak target in another sequence, 
            // but in this specific sequence (1, 3, 5, ...), i-1 and i+1 are valley/base indices (0, 2, 4, ...), 
            // so their values haven't been increased *in this sequence* based on the peak criteria.
            // However, to be safe and handle cascading increases correctly, we must use the current state.

            long targetVal = Math.max(currentNums1[i - 1], currentNums1[i + 1]) + 1;

            if (targetVal > currentNums1[i]) {
                long increase = targetVal - currentNums1[i];
                cost1 += increase;
                currentNums1[i] += increase;
            }
            // Note: By only increasing nums[i], we ensure nums[i] is a peak relative to its current neighbors.
            // Since we fix the pattern, we don't worry about neighbors becoming peaks accidentally, 
            // as they are designated as non-peaks (valleys or bases).
        }

        // Case 2: Peaks at 2, 4, 6, ...
        long cost2 = 0;
        long[] currentNums2 = Arrays.copyOf(nums, n);

        // Iterate over potential peak indices i = 2, 4, 6, ...
        for (int i = 2; i <= n - 2; i += 2) {
            // Target: currentNums2[i] > max(currentNums2[i-1], currentNums2[i+1])

            long targetVal = Math.max(currentNums2[i - 1], currentNums2[i + 1]) + 1;

            if (targetVal > currentNums2[i]) {
                long increase = targetVal - currentNums2[i];
                cost2 += increase;
                currentNums2[i] += increase;
            }
        }

        // The minimum cost to achieve the maximum number of peaks (which is achieved by these two configurations)
        return Math.min(cost1, cost2);
    }
}
