        // The maximum number of peaks achievable is M = ceil((n-2)/2).
        // We check two primary patterns that achieve this maximum:
        // Pattern 1: Peaks at indices 1, 3, 5, ...
        // Pattern 2: Peaks at indices 2, 4, 6, ...

        // --- Case 1: Peaks at 1, 3, 5, ... ---
        long cost1 = 0;
        long[] currentNums1 = Arrays.copyOf(nums, n);

