    // Since a peak at i depends on i-1 and i+1, a standard linear DP is tricky because of lookahead.

    // A simpler DP approach is to decide for each index i (1 to n-2) whether it will be a peak or not,
    // ensuring the structural constraints are met (peaks must be separated by at least one non-peak valley/plateau).

    // Let dp[i][k] be the minimum cost considering indices up to i, having formed k peaks.
    // State must also track the relationship between i and i-1 to enforce spacing.

    // Let dp[i][j] = minimum cost considering prefix nums[0...i] such that we have exactly j peaks *among indices 1 to i-1*.
    // Index i can be:
    // 0: Not a peak, and not required to be a valley/low point relative to i-1 (i.e., nums[i] >= nums[i-1])
    // 1: A peak (requires nums[i] > nums[i-1] and nums[i] > nums[i+1] - this requires lookahead!)
    // 2: A valley/low point relative to i-1 (i.e., nums[i] < nums[i-1])

    // This confirms that standard local DP is hard due to the neighbor constraint.
    // Since we are trying to maximize peaks first, we fix the *target* indices for peaks: $i_1, i_2, ..., i_M$.
    // The best target indices are typically $1, 3, 5, \dots$ or $2, 4, 6, \dots$

    // Case 1: Peaks at $1, 3, 5, \dots$
    let cost1 = 0;
    let currentNums1 = [...nums];

    for (let i = 1; i <= n - 2; i += 2) {
        // Target: currentNums1[i] must be a peak w.r.t currentNums1[i-1] and currentNums1[i+1].
        // Since we iterate sequentially, currentNums1[i-1] and currentNums1[i+1] might have already been increased 
        // due to prior peak creations (e.g., if i-2 was a peak).

        // To simplify, let's only enforce the requirement relative to the *original* neighbors, 
        // and assume that by increasing nums[i], we maintain the relative order for future steps 
        // (this is a strong assumption, but necessary for a greedy/fixed structure approach).

        // If we enforce the target structure $P, V, P, V, ...$ where $P$ is peak, $V$ is valley/base.
        // Indices 0, 2, 4, ... are low points/bases. Indices 1, 3, 5, ... are peaks.

        // Target Peak at i (odd): nums[i] > max(nums[i-1], nums[i+1])
        let target_val = Math.max(currentNums1[i - 1], currentNums1[i + 1]) + 1;

        if (target_val > currentNums1[i]) {
            const increase = target_val - currentNums1[i];
            cost1 += increase;
            currentNums1[i] += increase;
        }

        // Crucially, we must also ensure that the neighbors don't become peaks accidentally due to increases at i.
        // If we only increase nums[i], the neighbors nums[i-1] and nums[i+1] do not change, so they won't become peaks if they weren't already.
        // The neighbors must be $\le$ the target peak value. Since we set nums[i] > max(neighbors), this is guaranteed.
        // We must also ensure neighbors are not peaks themselves. E.g., nums[i-1] should not be a peak relative to nums[i-2] and nums[i].
        // If i-2 was a peak, nums[i-1] is a valley relative to i-2. Increasing i doesn't change that.

        // This greedy approach seems plausible if we fix the target positions $1, 3, 5, \dots$.
    }

    // Case 2: Peaks at $2, 4, 6, \dots$
    let cost2 = 0;
    let currentNums2 = [...nums];

    for (let i = 2; i <= n - 2; i += 2) {
        // Target Peak at i (even): nums[i] > max(nums[i-1], nums[i+1])
        let target_val = Math.max(currentNums2[i - 1], currentNums2[i + 1]) + 1;

        if (target_val > currentNums2[i]) {
            const increase = target_val - currentNums2[i];
            cost2 += increase;
            currentNums2[i] += increase;
        }
    }

    // The minimum cost among these two maximal configurations is the answer.
    return Math.min(cost1, cost2);
}
